if (req.headers['x-admin'] === 'true') {
```

**Fix**: Implement proper authentication using JWT tokens or sessions:
```javascript
function checkAdmin(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'No token provided' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    if (decoded.role !== 'admin') {
      return res.status(403).json({ error: 'Admin access required' });
    }
    req.user = decoded;
    next();
  } catch (error) {
    return res.status(401).json({ error: 'Invalid token' });
  }
}
```

### 2. **Information Disclosure**
**Problem**: Generic error message reveals the existence of admin functionality.

**Fix**: Use consistent error messages:
```javascript
res.status(403).json({ error: 'Access denied' });
```

## Logic Bugs

### 3. **Missing Return Statement**
**Problem**: When authentication fails, the function continues executing after sending the response.

**Fix**: Add `return` statement:
```javascript
} else {
  return res.status(403).json({ error: 'Access denied' });
}
```

### 4. **No Error Handling**
**Problem**: No handling for malformed headers or unexpected errors.

**Fix**: Add try-catch blocks and input validation as shown in the JWT example above.

## Improvements

### 5. **Add Request Logging**
```javascript
function checkAdmin(req, res, next) {
  console.log(`Admin access attempt from IP: ${req.ip}`);
  // ... rest of authentication logic
}
```

### 6. **Rate Limiting**
Implement rate limiting for admin endpoints:
```javascript
const rateLimit = require('express-rate-limit');

const adminRateLimit = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // limit each IP to 10 requests per windowMs
  message: 'Too many admin requests'
});
```

